const now = new Date();
const day = now.getDay();
const daysSinceMonday = (day + 6) % 7;
const thisMonday = new Date(now);
thisMonday.setDate(now.getDate() - daysSinceMonday);
thisMonday.setHours(0, 0, 0, 0);
const lastMonday = new Date(thisMonday);
lastMonday.setDate(thisMonday.getDate() - 7);
const lastSunday = new Date(thisMonday);
lastSunday.setDate(thisMonday.getDate() - 1);
const pad = (value) => String(value).padStart(2, '0');
const fmt = (date) => `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
const parsedMinStars = Number($env.GITHUB_WEEKLY_MIN_STARS || 50);
const minStars = Number.isFinite(parsedMinStars) ? parsedMinStars : 50;
const parsedLimit = Number($env.GITHUB_WEEKLY_LIMIT || 10);
const limit = Math.min(Math.max(Number.isFinite(parsedLimit) ? parsedLimit : 10, 1), 100);
const language = ($env.GITHUB_WEEKLY_LANGUAGE || '').trim();
const languageQuery = language ? ` language:${language}` : '';
const q = `created:${fmt(lastMonday)}..${fmt(lastSunday)} fork:false archived:false stars:>${minStars}${languageQuery}`;
return [{
  json: {
    startDate: fmt(lastMonday),
    endDate: fmt(lastSunday),
    minStars,
    limit,
    language,
    q,
    trigger_type: 'command',
    input: $json.input || $json.command_text || '',
  },
}];

