const source = $input.first().json;
const query = $('Build Command GitHub Query').first().json;
const repos = (source.items || []).map((repo) => ({
  full_name: repo.full_name,
  html_url: repo.html_url,
  description: repo.description,
  stargazers_count: repo.stargazers_count,
  language: repo.language,
  created_at: repo.created_at,
  owner: repo.owner ? { login: repo.owner.login, html_url: repo.owner.html_url } : undefined,
  topics: repo.topics || [],
}));
const lines = [`上周 GitHub 高星新项目 Top ${repos.length}（${query.startDate} 至 ${query.endDate}）`];
lines.push(`筛选：stars > ${query.minStars}${query.language ? `，语言：${query.language}` : ''}`);
if (!repos.length) {
  lines.push('没有找到符合条件的新项目，可以降低 GITHUB_WEEKLY_MIN_STARS 或清空 GITHUB_WEEKLY_LANGUAGE。');
} else {
  repos.forEach((repo, index) => {
    const stars = Number(repo.stargazers_count || 0).toLocaleString('en-US');
    const lang = repo.language || 'Unknown';
    const desc = repo.description || '暂无描述';
    lines.push('');
    lines.push(`${index + 1}. ${repo.full_name} - ${stars} stars`);
    lines.push(`   ${desc}`);
    lines.push(`   语言：${lang}`);
    lines.push(`   ${repo.html_url}`);
  });
}
return [{
  json: {
    text: lines.join('\n'),
    data: {
      startDate: query.startDate,
      endDate: query.endDate,
      minStars: query.minStars,
      limit: query.limit,
      language: query.language,
      count: repos.length,
      totalCount: source.total_count || 0,
      incompleteResults: Boolean(source.incomplete_results),
      repos,
    },
    metadata: {
      source: 'github_weekly_stars',
      trigger_type: query.trigger_type,
      q: query.q,
      generated_at: new Date().toISOString(),
    },
  },
}];

